/**
 * Crops a marker which has one, or both sides out of bounds
 *
 * @param originalX - the marker X position
 * @param originalWidth - the marker width
 * @param trackWidth - the track width
 *
 * @returns cropped marker x, width and crop options
 */
export const cropMarker = (
  originalX: number,
  originalWidth: number,
  trackWidth: number,
) => {
  let croppedX = originalX;
  let croppedWidth = originalWidth;

  if (croppedX < 0) {
    croppedWidth += croppedX; // subtract negative x from width to crop the marker
    croppedX = 0; // clamp value to start edge
  }

  if (croppedX + croppedWidth > trackWidth) {
    croppedWidth = trackWidth - croppedX; // clamp width to the end edge
  }

  return {
    croppedWidth,
    croppedX,
  };
};
